+  private getFindCursor(opts: CrudOptions): {
+    values: Record<string, any>;
+    sort: [string, 'asc' | 'desc'][];
+  } | null {
+    if (!opts.cursor) {
+      return null;
+    }
+    if (!opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+
+    let values: Record<string, any>;
+    try {
+      values = JSON.parse(Buffer.from(opts.cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!values || Array.isArray(values) || typeof values !== 'object') {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!(this.crudConfig.id_field in values)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+
+    const sort = this.getCursorOrderBy(opts.orderBy) as [
+      string,
+      'asc' | 'desc',
+    ][];
+    const serializedSort = sort.map(([field, dir]) => `${field}:${dir}`).join(',');
+    if (values.__sort !== serializedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (sort.some(([field]) => !(field in values))) {
+      throw new BadRequestException('cursor is missing a sort field');
+    }
+    return { values, sort };
+  }
+
+  private getCursorOrderBy(
+    orderBy: any,
+    expectedSort?: [string, 'asc' | 'desc'][],
+  ): [string, 'asc' | 'desc'][] {
+    const sort: [string, 'asc' | 'desc'][] = [];
+    for (const part of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      for (const [field, value] of Object.entries(part || {})) {
+        const dir = String(value).toLowerCase().split(' ')[0];
+        if (dir !== 'asc' && dir !== 'desc') {
+          throw new BadRequestException('cursor pagination requires asc or desc orderBy');
+        }
+        sort.push([field, dir]);
+      }
+    }
+    if (!sort.length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (!sort.some(([field]) => field === this.crudConfig.id_field)) {
+      sort.push([this.crudConfig.id_field, 'asc']);
+    }
+    if (
+      expectedSort &&
+      (expectedSort.length !== sort.length ||
+        expectedSort.some(([field, dir], i) =>
+          field !== sort[i][0] || dir !== sort[i][1],
+        ))
+    ) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    return sort;
+  }
+
+  private getCursorQuery(
+    sort: [string, 'asc' | 'desc'][],
+    values: Record<string, any>,
+  ) {
+    return {
+      $or: sort.map(([field, dir], index) => ({
+        ...Object.fromEntries(sort.slice(0, index).map(([f]) => [f, values[f]])),
+        [field]: { [dir === 'asc' ? '$gt' : '$lt']: values[field] },
+      })),
+    };
+  }
+
+  private createFindCursor(entity: T, sort: [string, 'asc' | 'desc'][]) {
+    const values: Record<string, any> = {
+      __sort: sort.map(([field, dir]) => `${field}:${dir}`).join(','),
+    };
+    for (const [field] of sort) {
+      values[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(values)).toString('base64');
+  }
